      // Map predicates to the appropriate boundary.
      APFloat Boundary = C_narrow; // default
      bool Valid = true;

      switch (Pred) {
      default:
        Valid = false;
        break;
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
        // trunc(X) >= C  ->  X >= boundary(C)
        Boundary = getBoundary(C_narrow);
        break;
      case FCmpInst::FCMP_OLT:
      case FCmpInst::FCMP_ULT:
        // trunc(X) < C  ->  X < boundary(C)
        Boundary = getBoundary(C_narrow);
        break;
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_UGT:
        // trunc(X) > C  ->  X > nextDown(boundary(nextUp(C)))
        Boundary = getBoundary(NextC_narrow);
        Boundary.next(true); // nextDown -> largest value that truncates to <= C
        break;
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
        // trunc(X) <= C  ->  X <= nextDown(boundary(nextUp(C)))
        Boundary = getBoundary(NextC_narrow);
        Boundary.next(true); // nextDown -> largest value that truncates to <= C
        break;
      }
CODEEOF"}

